const content = $input.first().json.choices[0].message.content.trim();
const userId = $('Buscar usuário').first().json.id;
const phone = $('Extrair dados').first().json.remoteJid;
try {
  const jsonMatch = content.match(/\{[^{}]+\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    if (parsed.intent === 'registrar_receita') {
      const rt = 'Show! 💰 Receita anotada:\n\n*+R$ ' + Number(parsed.amount||0).toFixed(2).replace('.',',') + '* — ' + (parsed.description||parsed.client_name||'serviço') + '\n📅 Hoje\n\n🔗 https://socio-painel.vercel.app';
      return [{ json: { intent: parsed.intent, amount: parsed.amount, description: parsed.description, client_name: parsed.client_name||'', responseText: rt, userId, phone } }];
    }
    if (parsed.intent === 'registrar_despesa') {
      const rt = 'Anotado! 📝 Despesa:\n\n*-R$ ' + Number(parsed.amount||0).toFixed(2).replace('.',',') + '* — ' + (parsed.description||'despesa') + '\n📅 Hoje\n\n🔗 https://socio-painel.vercel.app';
      return [{ json: { intent: parsed.intent, amount: parsed.amount, description: parsed.description, client_name: parsed.client_name||'', responseText: rt, userId, phone } }];
    }
    if (parsed.intent === 'registrar_agendamento') {
      const rt = '📅 *Agendamento confirmado!*\n\n👤 ' + (parsed.client_name||'') + '\n📋 ' + (parsed.service||'') + '\n🕐 ' + (parsed.scheduled_at||'').slice(0,16).replace('T',' ') + '\n💰 R$ ' + Number(parsed.price||0).toFixed(2).replace('.',',') + '\n\n🔗 https://socio-painel.vercel.app/agenda';
      return [{ json: { intent: parsed.intent, service: parsed.service, client_name: parsed.client_name, scheduled_at: parsed.scheduled_at, price: parsed.price||0, responseText: rt, userId, phone } }];
    }
    if (parsed.intent === 'definir_meta') {
      const rt = '🎯 Meta definida!\n\n*R$ ' + Number(parsed.amount||0).toFixed(2).replace('.',',') + '* este mês.\n\nVou te avisar o progresso todo dia! 💪';
      return [{ json: { intent: parsed.intent, amount: parsed.amount, responseText: rt, userId, phone } }];
    }
    if (parsed.intent === 'registrar_tarefa') {
      const rt = '✅ Anotei!\n\n📝 *' + (parsed.title||'') + '*\nPrioridade: ' + (parsed.priority||'média');
      return [{ json: { intent: parsed.intent, title: parsed.title, priority: parsed.priority||'media', responseText: rt, userId, phone } }];
    }
    if (parsed.intent === 'registrar_pagamento_futuro') {
      const rt = '📋 Pagamento agendado!\n\n💸 *' + (parsed.description||'Pagamento') + '*\nValor: R$ ' + Number(parsed.amount||0).toFixed(2).replace('.',',');
      return [{ json: { intent: parsed.intent, amount: parsed.amount||0, description: parsed.description, due_date: parsed.due_date, responseText: rt, userId, phone } }];
    }
    if (parsed.intent === 'registrar_custo_recorrente') {
      const rt = '🔄 Custo fixo cadastrado!\n\n📝 *' + (parsed.name||'') + '*\nR$ ' + Number(parsed.amount||0).toFixed(2).replace('.',',') + '/mês';
      return [{ json: { intent: parsed.intent, name: parsed.name, amount: parsed.amount||0, due_day: parsed.due_day, responseText: rt, userId, phone } }];
    }
  }
} catch(e) {}

// Fallback: GPT retornou texto formatado em vez de JSON
// Detectar pelo padrão de resposta de custo recorrente
if (content.includes('Custo fixo cadastrado') || content.includes('/mês')) {
  // Tentar extrair dados do texto de confirmação
  const amtMatch = content.match(/R\$\s*([\d.,]+)/);
  const dayMatch = content.match(/dia (\d+)/);
  const nameMatch = content.match(/\*([^*]+)\*/);
  if (amtMatch) {
    const amount = parseFloat(amtMatch[1].replace('.','').replace(',','.'));
    const name = nameMatch ? nameMatch[1].trim() : 'Custo fixo';
    const due_day = dayMatch ? parseInt(dayMatch[1]) : null;
    const rt = '🔄 Custo fixo cadastrado!\n\n📝 *' + name + '*\nR$ ' + amount.toFixed(2).replace('.',',') + '/mês' + (due_day ? '\n📅 Todo dia ' + due_day : '');
    return [{ json: { intent: 'registrar_custo_recorrente', name, amount, due_day, responseText: rt, userId, phone } }];
  }
}
return [{ json: { intent: 'resposta', responseText: content, userId, phone } }];

