const userData = $('Extrair dados').first().json;
return [{ json: { ...userData, text: transcription.trim(), isAudio: false } }];

const u = $('Buscar usuário').first().json || {};
const extrair = $('Extrair dados').first().json || {};
const txs = (() => { try { return $('Buscar últimas transações').all().map(i => i.json).filter(t => t && t.amount); } catch(e) { return []; } })();
const agenda = (() => { try { return $('Buscar agenda proximos dias').all().map(i => i.json).filter(a => a && a.scheduled_at); } catch(e) { return []; } })();
const tarefas = (() => { try { return $('Buscar tarefas pendentes ctx').all().map(i => i.json).filter(t => t && t.title); } catch(e) { return []; } })();
const historico = (() => { try { const items = $('Buscar histórico msgs').all().map(i => i.json).filter(h => h && h.content && !h.error); return items.reverse(); } catch(e) { return []; } })();

const receita = txs.filter(t => t.type==='receita').reduce((s,t)=>s+parseFloat(t.amount||0),0);
const despesa = txs.filter(t => t.type==='despesa').reduce((s,t)=>s+parseFloat(t.amount||0),0);
const agendaStr = agenda.length ? agenda.map(a=>{const dt=new Date(a.scheduled_at);const d=dt.toLocaleDateString('pt-BR',{timeZone:'America/Sao_Paulo',day:'2-digit',month:'2-digit'});const h=dt.toLocaleTimeString('pt-BR',{timeZone:'America/Sao_Paulo',hour:'2-digit',minute:'2-digit'});return d+' '+h+' - '+(a.service||'?')+' com '+(a.client_name||'?');}).join('; ') : 'Nenhum agendamento';
const tarefasStr = tarefas.length ? tarefas.map(t=>t.title).join('; ') : 'Nenhuma tarefa';

const primeiroNome = (u.name||'').split(' ')[0] || 'você';
const sistema = 'Você é o Sócio 🤝 — assistente pessoal de negócios de ' + (u.name||'você') + ' no WhatsApp. O nome do seu dono é ' + primeiroNome + ' — chame-o pelo primeiro nome nas respostas. Hoje: ' + new Date().toLocaleDateString('pt-BR') + ' (' + new Date().toISOString().substring(0,10) + ')\n\n📊 RESUMO DO MÊS:\n💰 Receitas: R$ ' + receita.toFixed(2) + '\n💸 Despesas: R$ ' + despesa.toFixed(2) + '\n✅ Líquido: R$ ' + (receita-despesa).toFixed(2) + '\n🎯 Meta: R$ ' + (u.monthly_goal||0) + '\n\n📅 AGENDA PRÓXIMOS 7 DIAS: ' + agendaStr + '\n📌 TAREFAS: ' + tarefasStr + '\n🔄 ÚLTIMAS TRANSAÇÕES: ' + JSON.stringify(txs.slice(0,5)) + '\n\nREGRAS:\n- Use o histórico abaixo para entender respostas curtas (\'Amanhã\', \'Sim\', números).\n- Dados não informados: horário padrão 09:00, preço 0.\n- Use emojis de forma natural: 💰 dinheiro, 📅 agenda, ✅ confirmação, ⚠️ alertas, 🎉 comemorações.\n- REGISTRAR → OBRIGATÓRIO: responda EXCLUSIVAMENTE com JSON puro, sem nenhum texto antes ou depois. NUNCA responda com texto de confirmação para registros — apenas JSON:\n  Receita: {"intent":"registrar_receita","amount":NUM,"description":"DESC","client_name":""}\n  Despesa: {"intent":"registrar_despesa","amount":NUM,"description":"DESC","client_name":""}\n  Agendamento: {"intent":"registrar_agendamento","service":"SVC","client_name":"NOME","scheduled_at":"YYYY-MM-DDTHH:MM:00","price":0} — scheduled_at SEMPRE no horário de Brasília (NÃO converter para UTC). Para datas relativas: "amanhã"=hoje+1, "sexta-feira"=calcule o próximo dia correto baseado na data ISO de Hoje acima\n  Meta: {"intent":"definir_meta","amount":NUM}\n  Tarefa: {"intent":"registrar_tarefa","title":"TITULO","priority":"alta|media|baixa"}\n  Pgto avulso: {"intent":"registrar_pagamento_futuro","amount":NUM,"description":"DESC","due_date":"YYYY-MM-DD"}\n  Custo recorrente: {"intent":"registrar_custo_recorrente","name":"NOME","amount":NUM,"due_day":NUM}\n- CONSULTAR → responda de forma direta e amigável com os dados disponíveis.\n- Só peça mais informações se realmente necessário.\n- RECORRENTE (ex: \'aluguel todo dia 5\'): {"intent":"registrar_custo_recorrente","name":"NOME","amount":NUM,"due_day":NUM}\n- AVULSO (ex: \'pagar Leo dia 20\'): {"intent":"registrar_pagamento_futuro","amount":NUM,"description":"DESC","due_date":"YYYY-MM-DD"} — assume mês atual se não informado.\n- client_name: use o NOME DO CLIENTE se houver. Sem cliente especifico (gastos gerais, locais, enderecos) use string vazia. Local como churrascaria Rondon NAO e cliente. NUNCA retorne as palavras vazio ou null no campo client_name.\n- Tom: moderno, acolhedor, direto — como um amigo entendido de negócios. Máximo 5 linhas.\n- Corrija erros de digitação e capitalização nas respostas.';

// Para mensagens de áudio, usar transcrição em vez de '__audio__'
let currentText = String(extrair.text || '');
try {
  const audioTranscription = $('Montar texto do áudio').first().json.text;
  if (audioTranscription && audioTranscription !== '__audio__' && audioTranscription.trim().length > 0) {
    currentText = audioTranscription.trim();
  }
} catch(e) { /* não é fluxo de áudio, manter texto original */ }

// Build history, removing duplicates of the current message at the END
// (happens when Evolution API saves message before history is fetched)
const histMsgs = historico
  .map(h => ({ role: h.direction === 'inbound' ? 'user' : 'assistant', content: String(h.content) }));

// Remove last item if it's the same as current user message (dedup)
if (histMsgs.length > 0) {
  const last = histMsgs[histMsgs.length - 1];
  if (last.role === 'user' && last.content === currentText) {
    histMsgs.pop();
  }
}

const messages = [{ role: 'system', content: sistema }].concat(histMsgs).concat([{ role: 'user', content: currentText }]);

return [{ json: { gptBody: JSON.stringify({ model: 'gpt-4o-mini', temperature: 0.3, messages: messages }) } }];

const base64Raw = ($('Baixar áudio').first().json.base64 || '');
const base64Data = base64Raw.replace(/^data:[^;]+;base64,/, '');
if (!base64Data) {
  return [{ json: { hasAudio: false }, binary: {} }];
}
return [{
  json: { hasAudio: true },
  binary: {
    data: {
      data: base64Data,
      mimeType: 'audio/ogg',
      fileName: 'audio.ogg',
    }
  }
}];

