} else if (data.messageType === 'extendedTextMessage') {
  text = data.message?.extendedTextMessage?.text || '';
} else if (data.messageType === 'audioMessage') {
  isAudio = true;
  text = '__audio__';
}
const phoneShort = phone.startsWith('55') ? phone.slice(2) : phone;
return [{ json: { phone, phoneShort, remoteJid, pushName: data.pushName || 'Amigo', text: text.trim(), isAudio, messageKey: key, instanceName: body.instance } }];

